"use client";

import { useState, useEffect, useCallback } from "react";
import { ShieldCheck, LineChart, Star, ChevronRight, X, Zap } from "lucide-react";

const ONBOARDING_KEY = "365_onboarding_done";

interface Step {
    icon: React.ReactNode;
    title: string;
    subtitle: string;
    body: string;
    highlight?: string;
}

const STEPS: Step[] = [
    {
        icon: <Zap size={28} className="text-[#d4af37]" />,
        title: "Welcome to 365 Advisers",
        subtitle: "Step 1 of 3",
        body: "Type any stock ticker (e.g. NVDA, AAPL) in the search bar and click Analyze. The Investment Committee will run fundamental, technical, and combined analysis simultaneously.",
        highlight: "Institutional-grade analysis in under 60 seconds.",
    },
    {
        icon: <ShieldCheck size={28} className="text-[#d4af37]" />,
        title: "Reading the Committee Verdict",
        subtitle: "Step 2 of 3",
        body: "The Investment Committee Verdict synthesizes 4 institutional frameworks into a single score (0–10), a signal (BUY · HOLD · SELL), and an actionable narrative — the same process used by professional investment committees.",
        highlight: "Score ≥ 7 = Bullish · Score 5–6 = Neutral · Score ≤ 4 = Bearish",
    },
    {
        icon: <Star size={28} className="text-[#d4af37]" />,
        title: "Build Your Coverage List",
        subtitle: "Step 3 of 3",
        body: "Click the ★ button after any analysis to add the asset to your watchlist. Your Coverage List tracks signals, scores, and changes over time — so you can re-run analysis with one click.",
        highlight: "Pro tip: re-analyze regularly to track score deltas.",
    },
];

interface OnboardingOverlayProps {
    onDone: () => void;
}

export default function OnboardingOverlay({ onDone }: OnboardingOverlayProps) {
    const [step, setStep] = useState(0);
    const [visible, setVisible] = useState(false);

    useEffect(() => {
        // Trigger entrance animation after mount
        const t = setTimeout(() => setVisible(true), 50);
        return () => clearTimeout(t);
    }, []);

    const dismiss = useCallback(() => {
        try { localStorage.setItem(ONBOARDING_KEY, "1"); } catch { /* ignore */ }
        setVisible(false);
        setTimeout(onDone, 350); // wait for exit animation
    }, [onDone]);

    useEffect(() => {
        const handler = (e: KeyboardEvent) => { if (e.key === "Escape") dismiss(); };
        window.addEventListener("keydown", handler);
        return () => window.removeEventListener("keydown", handler);
    }, [dismiss]);

    const isLast = step === STEPS.length - 1;
    const current = STEPS[step];

    return (
        <div
            className="fixed inset-0 z-[100] flex items-center justify-center p-4"
            style={{
                backgroundColor: `rgba(0,0,0,${visible ? 0.7 : 0})`,
                backdropFilter: visible ? "blur(6px)" : "blur(0px)",
                transition: "background-color 0.35s ease, backdrop-filter 0.35s ease",
            }}
            onClick={(e) => e.target === e.currentTarget && dismiss()}
        >
            <div
                className="relative bg-[#0d1117] border border-[#30363d] rounded-2xl p-8 max-w-md w-full shadow-2xl"
                style={{
                    transform: visible ? "translateY(0) scale(1)" : "translateY(24px) scale(0.95)",
                    opacity: visible ? 1 : 0,
                    transition: "transform 0.35s cubic-bezier(0.34, 1.56, 0.64, 1), opacity 0.35s ease",
                }}
            >
                {/* Close */}
                <button
                    onClick={dismiss}
                    className="absolute top-4 right-4 text-gray-600 hover:text-gray-400 transition-colors"
                    title="Skip onboarding"
                >
                    <X size={16} />
                </button>

                {/* Step indicator dots */}
                <div className="flex gap-1.5 mb-6">
                    {STEPS.map((_, i) => (
                        <div
                            key={i}
                            className={`h-1 rounded-full transition-all duration-300 ${i === step ? "w-6 bg-[#d4af37]" : "w-2 bg-[#30363d]"
                                }`}
                        />
                    ))}
                </div>

                {/* Icon */}
                <div className="w-14 h-14 bg-[#161b22] border border-[#d4af37]/20 rounded-2xl flex items-center justify-center mb-5">
                    {current.icon}
                </div>

                {/* Content */}
                <p className="text-[9px] font-mono text-gray-600 uppercase tracking-widest mb-1">
                    {current.subtitle}
                </p>
                <h2 className="text-lg font-black text-white mb-3">{current.title}</h2>
                <p className="text-sm text-gray-400 leading-relaxed mb-4">{current.body}</p>

                {current.highlight && (
                    <div className="bg-[#d4af37]/8 border border-[#d4af37]/20 rounded-lg px-4 py-2.5 mb-5">
                        <p className="text-[10px] font-mono text-[#d4af37]/80">{current.highlight}</p>
                    </div>
                )}

                {/* Actions */}
                <div className="flex items-center justify-between">
                    <button
                        onClick={dismiss}
                        className="text-[10px] text-gray-600 hover:text-gray-400 transition-colors uppercase tracking-widest font-bold"
                    >
                        Skip
                    </button>

                    <button
                        onClick={() => isLast ? dismiss() : setStep(s => s + 1)}
                        className="flex items-center gap-2 bg-[#d4af37] text-black text-sm font-black px-5 py-2 rounded-xl hover:bg-[#f9e29c] transition-all"
                    >
                        {isLast ? "Get Started" : "Next"}
                        {!isLast && <ChevronRight size={14} />}
                    </button>
                </div>
            </div>
        </div>
    );
}

/** Hook to manage onboarding visibility — server-safe */
export function useOnboarding() {
    const [showOnboarding, setShowOnboarding] = useState(false);

    useEffect(() => {
        if (typeof window === "undefined") return;
        const done = localStorage.getItem(ONBOARDING_KEY);
        if (!done) setShowOnboarding(true);
    }, []);

    const dismiss = useCallback(() => setShowOnboarding(false), []);
    return { showOnboarding, dismiss };
}

"use client";

import { PieChart, List, FileWarning, RefreshCw, Briefcase, Plus, TrendingUp, TrendingDown, Copy, ShieldAlert, Activity } from "lucide-react";
import { useState, useMemo } from "react";
import type { PortfolioRecommendationResult, PortfolioPositionOutput } from "../hooks/usePortfolioBuilder";
import { usePortfolioBuilder } from "../hooks/usePortfolioBuilder";
import { HistoryEntry } from "../hooks/useAnalysisHistory";

interface PortfolioDashboardProps {
    historyEntries: HistoryEntry[];
}

export default function PortfolioDashboard({ historyEntries }: PortfolioDashboardProps) {
    const { buildPortfolio, result, isLoading, error, reset } = usePortfolioBuilder();

    // We only consider history entries that have finished successfully and generated position_sizing data
    const eligiblePositions = useMemo(() => {
        return historyEntries
            .filter(e => Number(e.fundamental_score) > 0 && e.opportunity_score !== undefined && e.position_sizing !== undefined)
            .map(e => ({
                ticker: e.ticker,
                sector: e.sector || "Unknown",
                opportunity_score: e.opportunity_score as number,
                dimensions: typeof e.dimensions === "string" ? JSON.parse(e.dimensions) : (e.dimensions || {}),
                position_sizing: typeof e.position_sizing === "string" ? JSON.parse(e.position_sizing) : e.position_sizing,
                date: e.timestamp
            }));
    }, [historyEntries]);

    // Ensure we send unique tickers to the builder (keep only the newest)
    const uniquePositionsToBuild = useMemo(() => {
        const map = new Map();
        for (const pos of eligiblePositions) {
            // Because historyEntries is sorted newest first, the first time we see a ticker it's the newest one
            if (!map.has(pos.ticker)) {
                map.set(pos.ticker, pos);
            }
        }
        return Array.from(map.values());
    }, [eligiblePositions]);

    const handleBuild = () => {
        if (uniquePositionsToBuild.length === 0) return;
        buildPortfolio(uniquePositionsToBuild);
    };

    return (
        <div className="space-y-6" style={{ animation: "fadeSlideIn 0.4s ease both" }}>
            {/* Header */}
            <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
                <div>
                    <div className="flex items-center gap-2 mb-1">
                        <Briefcase size={14} className="text-[#60a5fa]" />
                        <h2 className="text-[9px] font-black uppercase tracking-[0.2em] text-gray-500">Portfolio Construction Engine</h2>
                    </div>
                </div>

                <div className="flex gap-2">
                    <button
                        onClick={handleBuild}
                        disabled={isLoading || uniquePositionsToBuild.length === 0}
                        className="flex items-center gap-1.5 text-[8px] font-bold bg-[#60a5fa]/10 text-[#60a5fa] border border-[#60a5fa]/30 hover:bg-[#60a5fa]/20 px-3 py-1.5 rounded transition-colors tracking-wider uppercase disabled:opacity-50"
                    >
                        {isLoading ? <RefreshCw size={10} className="animate-spin" /> : <Plus size={10} />}
                        Build Portfolio ({uniquePositionsToBuild.length} Assets)
                    </button>
                    {result && (
                        <button
                            onClick={reset}
                            className="flex items-center gap-1.5 text-[8px] font-bold text-gray-500 hover:text-white px-3 py-1.5 border border-[#30363d] rounded transition-colors tracking-wider uppercase"
                        >
                            Reset
                        </button>
                    )}
                </div>
            </div>

            {/* Empty State */}
            {uniquePositionsToBuild.length === 0 && !result && (
                <div className="glass-card p-12 flex flex-col items-center justify-center text-center border-dashed border-[#30363d]">
                    <PieChart size={32} className="text-[#30363d] mb-4" />
                    <p className="text-sm font-bold text-gray-400 mb-2">No Assets in Memory</p>
                    <p className="text-[10px] text-gray-500 max-w-sm leading-relaxed">
                        Analyze symbols first. The Portfolio Engine will use your Analysis History to construct a Risk-Adjusted Core-Satellite Portfolio automatically.
                    </p>
                </div>
            )}

            {/* Error */}
            {error && (
                <div className="bg-red-500/10 border border-red-500/30 text-red-400 px-4 py-3 rounded flex items-start gap-3">
                    <ShieldAlert size={14} className="mt-0.5 flex-shrink-0" />
                    <p className="text-xs">{error}</p>
                </div>
            )}

            {/* Pre-Build Warning */}
            {uniquePositionsToBuild.length > 0 && !result && !isLoading && !error && (
                <div className="glass-card p-6 border-l-2 border-l-[#60a5fa]">
                    <div className="flex items-center gap-3 mb-4">
                        <Activity size={16} className="text-[#60a5fa]" />
                        <h3 className="text-sm font-black text-white">Ready to Construct</h3>
                    </div>
                    <p className="text-xs text-gray-400 mb-4 leading-relaxed">
                        The engine found {uniquePositionsToBuild.length} unique analyzed assets in your history. Click "Build Portfolio" to automatically categorize them into Core/Satellite buckets, apply risk volatility limits, and optimize sector exposures.
                    </p>
                    <div className="flex flex-wrap gap-2">
                        {uniquePositionsToBuild.map(p => (
                            <span key={p.ticker} className="bg-[#161b22] border border-[#30363d] text-gray-400 text-[9px] font-mono px-2 py-1 rounded">
                                {p.ticker}
                            </span>
                        ))}
                    </div>
                </div>
            )}

            {/* Results */}
            {result && (
                <div className="space-y-6" style={{ animation: "fadeSlideIn 0.5s ease both" }}>

                    {/* Top Stats */}
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                        <div className="glass-card p-4 border-[#30363d]">
                            <p className="text-[9px] font-black uppercase tracking-widest text-gray-500 mb-1">Total Allocated</p>
                            <p className="text-2xl font-black text-white font-mono">{result.total_allocation.toFixed(1)}%</p>
                        </div>
                        <div className="glass-card p-4 border border-[#d4af37]/30 bg-[#d4af37]/5">
                            <p className="text-[9px] font-black uppercase tracking-widest text-[#d4af37] mb-1">Core Block</p>
                            <p className="text-2xl font-black text-[#d4af37] font-mono">{result.core_allocation_total.toFixed(1)}%</p>
                        </div>
                        <div className="glass-card p-4 border border-[#60a5fa]/30 bg-[#60a5fa]/5">
                            <p className="text-[9px] font-black uppercase tracking-widest text-[#60a5fa] mb-1">Satellite Block</p>
                            <p className="text-2xl font-black text-[#60a5fa] font-mono">{result.satellite_allocation_total.toFixed(1)}%</p>
                        </div>
                        <div className="glass-card p-4 border-[#30363d]">
                            <p className="text-[9px] font-black uppercase tracking-widest text-gray-500 mb-1">Risk Profile</p>
                            <p className={`text-xl mt-1 font-black uppercase ${result.risk_level === "ELEVATED" ? "text-orange-400" : "text-green-400"}`}>
                                {result.risk_level}
                            </p>
                        </div>
                    </div>

                    {/* Violations */}
                    {result.violations_detected.length > 0 && (
                        <div className="bg-orange-500/10 border border-orange-500/20 p-4 rounded-xl">
                            <div className="flex items-center gap-2 mb-2">
                                <FileWarning size={14} className="text-orange-400" />
                                <p className="text-[10px] font-black uppercase tracking-widest text-orange-400">System Adjustments</p>
                            </div>
                            <ul className="space-y-1 pl-6 list-disc text-[11px] text-orange-200/80">
                                {result.violations_detected.map((v, i) => (
                                    <li key={i}>{v}</li>
                                ))}
                            </ul>
                        </div>
                    )}

                    {/* Positions Split */}
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        {/* CORE */}
                        <div className="glass-card p-5 border-t-2 border-[#d4af37]">
                            <div className="flex items-center justify-between mb-4 pb-2 border-b border-[#30363d]">
                                <h3 className="text-xs font-black uppercase tracking-widest text-[#d4af37]">Core Positions</h3>
                                <span className="text-[10px] bg-[#d4af37]/10 text-[#d4af37] px-2 py-0.5 rounded font-mono">{result.core_positions.length}</span>
                            </div>
                            <div className="space-y-2">
                                {result.core_positions.length === 0 ? (
                                    <p className="text-[10px] text-gray-500 italic">No assets qualified for CORE categorization.</p>
                                ) : (
                                    result.core_positions.map(p => (
                                        <div key={p.ticker} className="flex items-center justify-between bg-[#0d1117]/50 px-3 py-2 rounded">
                                            <div className="flex items-center gap-3">
                                                <span className="font-bold text-white text-sm w-12">{p.ticker}</span>
                                                <span className="text-[9px] uppercase tracking-wider text-gray-500 hidden sm:inline">{p.sector}</span>
                                            </div>
                                            <span className="font-mono text-sm font-black text-[#d4af37]">{p.target_weight.toFixed(1)}%</span>
                                        </div>
                                    ))
                                )}
                            </div>
                        </div>

                        {/* SATELLITE */}
                        <div className="glass-card p-5 border-t-2 border-[#60a5fa]">
                            <div className="flex items-center justify-between mb-4 pb-2 border-b border-[#30363d]">
                                <h3 className="text-xs font-black uppercase tracking-widest text-[#60a5fa]">Satellite Positions</h3>
                                <span className="text-[10px] bg-[#60a5fa]/10 text-[#60a5fa] px-2 py-0.5 rounded font-mono">{result.satellite_positions.length}</span>
                            </div>
                            <div className="space-y-2">
                                {result.satellite_positions.length === 0 ? (
                                    <p className="text-[10px] text-gray-500 italic">No assets qualified for SATELLITE categorization.</p>
                                ) : (
                                    result.satellite_positions.map(p => (
                                        <div key={p.ticker} className="flex items-center justify-between bg-[#0d1117]/50 px-3 py-2 rounded">
                                            <div className="flex items-center gap-3">
                                                <span className="font-bold text-white text-sm w-12">{p.ticker}</span>
                                                <span className="text-[9px] uppercase tracking-wider text-gray-500 hidden sm:inline">{p.sector}</span>
                                            </div>
                                            <span className="font-mono text-sm font-black text-[#60a5fa]">{p.target_weight.toFixed(1)}%</span>
                                        </div>
                                    ))
                                )}
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

"use client";

import { ShieldCheck, TrendingUp, TrendingDown, Minus, ChevronDown, ChevronUp, ExternalLink, Clock } from "lucide-react";
import { useState, useEffect } from "react";
import type { AgentMemo, CommitteeVerdict, FundamentalDataReady } from "@/hooks/useFundamentalStream";

// ─── Helpers ──────────────────────────────────────────────────────────────────

function signalColor(signal: string) {
    if (signal === "BUY") return "text-green-400";
    if (signal === "SELL" || signal === "AVOID") return "text-red-400";
    return "text-yellow-400";
}

function signalBg(signal: string) {
    if (signal === "BUY") return "bg-green-500/10 border-green-500/30";
    if (signal === "SELL" || signal === "AVOID") return "bg-red-500/10 border-red-500/30";
    return "bg-yellow-500/10 border-yellow-500/30";
}

function allocationColor(rec: string) {
    if (rec === "Overweight") return "text-green-400";
    if (rec === "Underweight" || rec === "Avoid") return "text-red-400";
    return "text-gray-400";
}

function ScoreRing({ score, size = 72 }: { score: number; size?: number }) {
    const [displayed, setDisplayed] = useState(0);

    useEffect(() => {
        let rafId: number;
        const duration = 800;
        const startTime = performance.now();
        const startVal = 0;

        const tick = (now: number) => {
            const elapsed = now - startTime;
            const progress = Math.min(elapsed / duration, 1);
            // easeOutCubic for a snappy deceleration
            const eased = 1 - Math.pow(1 - progress, 3);
            setDisplayed(startVal + eased * (score - startVal));
            if (progress < 1) {
                rafId = requestAnimationFrame(tick);
            }
        };

        rafId = requestAnimationFrame(tick);
        return () => cancelAnimationFrame(rafId);
    }, [score]);

    const radius = size / 2 - 6;
    const circumference = 2 * Math.PI * radius;
    const filled = (displayed / 10) * circumference;
    const color = score >= 7 ? "#4ade80" : score >= 5 ? "#d4af37" : "#f87171";

    return (
        <svg width={size} height={size} className="rotate-[-90deg]">
            <circle cx={size / 2} cy={size / 2} r={radius} fill="none" stroke="#21262d" strokeWidth={5} />
            <circle
                cx={size / 2} cy={size / 2} r={radius}
                fill="none" stroke={color} strokeWidth={5}
                strokeDasharray={`${filled} ${circumference}`}
                strokeLinecap="round"
            />
            <text
                x={size / 2} y={size / 2 + 1}
                textAnchor="middle" dominantBaseline="middle"
                fill="white" fontSize={size * 0.22} fontWeight="900"
                style={{ transform: `rotate(90deg) translateX(0)`, transformOrigin: `${size / 2}px ${size / 2}px` }}
            >
                {displayed.toFixed(1)}
            </text>
        </svg>
    );
}

// ─── Agent Memo Card ──────────────────────────────────────────────────────────

function AgentMemoCard({ memo, index }: { memo: AgentMemo; index: number }) {
    const [open, setOpen] = useState(false);
    const [frameworkName] = memo.framework.split("—");

    return (
        <div
            className={`glass-card p-4 border flex flex-col gap-3 ${signalBg(memo.signal)}`}
            style={{ animation: `fadeSlideIn 0.3s ease ${index * 0.08}s both` }}
        >
            {/* Header */}
            <div className="flex items-start justify-between gap-2">
                <div>
                    <p className="text-[10px] font-black uppercase tracking-widest text-gray-500 mb-0.5">
                        {frameworkName.trim()}
                    </p>
                    <p className="text-sm font-black text-white leading-tight">{memo.agent}</p>
                </div>
                <span className={`text-[9px] font-black px-2 py-1 rounded border uppercase flex-shrink-0 ${signalBg(memo.signal)} ${signalColor(memo.signal)}`}>
                    {memo.signal}
                </span>
            </div>

            {/* Conviction bar */}
            <div>
                <div className="flex justify-between text-[8px] text-gray-600 mb-1">
                    <span>Conviction</span>
                    <span className="font-mono font-bold text-gray-400">{(memo.conviction * 100).toFixed(0)}%</span>
                </div>
                <div className="h-1 bg-[#21262d] rounded-full overflow-hidden">
                    <div
                        className={`h-full rounded-full transition-all duration-700 ${memo.signal === "BUY" ? "bg-green-500" : memo.signal === "SELL" ? "bg-red-500" : "bg-yellow-500"}`}
                        style={{ width: `${memo.conviction * 100}%` }}
                    />
                </div>
            </div>

            {/* Memo text */}
            <p className="text-[11px] text-gray-400 leading-relaxed italic">&ldquo;{memo.memo}&rdquo;</p>

            {/* Expandable detail */}
            <button
                onClick={() => setOpen((o) => !o)}
                className="flex items-center gap-1 text-[8px] text-gray-600 hover:text-[#d4af37] transition-colors font-bold uppercase tracking-wider"
            >
                {open ? <ChevronUp size={10} /> : <ChevronDown size={10} />}
                {open ? "Less" : "Detail"}
            </button>

            {open && (
                <div className="space-y-2 text-[9px] border-t border-[#30363d] pt-2" style={{ animation: "fadeSlideIn 0.2s ease" }}>
                    {memo.key_metrics_used.length > 0 && (
                        <div>
                            <p className="text-gray-600 font-bold mb-1">Metrics Used</p>
                            <div className="flex flex-wrap gap-1">
                                {memo.key_metrics_used.map((m) => (
                                    <span key={m} className="bg-[#21262d] text-gray-400 px-1.5 py-0.5 rounded text-[8px] font-mono">{m}</span>
                                ))}
                            </div>
                        </div>
                    )}
                    {memo.catalysts.length > 0 && (
                        <div>
                            <p className="text-green-500/70 font-bold mb-1">Catalysts</p>
                            {memo.catalysts.map((c) => <p key={c} className="text-gray-400">↗ {c}</p>)}
                        </div>
                    )}
                    {memo.risks.length > 0 && (
                        <div>
                            <p className="text-red-500/70 font-bold mb-1">Risks</p>
                            {memo.risks.map((r) => <p key={r} className="text-gray-400">↘ {r}</p>)}
                        </div>
                    )}
                </div>
            )}
        </div>
    );
}

// ─── Research Memo Card ───────────────────────────────────────────────────────

interface ResearchMemoCardProps {
    dataReady: FundamentalDataReady | null;
    agentMemos: AgentMemo[];
    committee: CommitteeVerdict | null;
    researchMemo: string | null;
    agentCount: number;
    totalAgents: number;
    status: string;
}

export default function ResearchMemoCard({
    dataReady,
    agentMemos,
    committee,
    researchMemo,
    agentCount,
    totalAgents,
    status,
}: ResearchMemoCardProps) {
    const [memoExpanded, setMemoExpanded] = useState(false);
    const [agentMemosOpen, setAgentMemosOpen] = useState(false);

    if (!dataReady) return null;

    return (
        <div className="space-y-6" style={{ animation: "fadeSlideIn 0.4s ease both" }}>

            {/* ── Committee Verdict Header ─── */}
            {committee && (
                <div className="glass-card p-6 border-[#d4af37]/30 bg-[#d4af37]/5" style={{ animation: "verdictReveal 0.7s cubic-bezier(0.34, 1.56, 0.64, 1) 0.1s both" }}>
                    <div className="flex flex-col sm:flex-row items-start sm:items-center gap-6">

                        {/* Score ring */}
                        <div className="flex-shrink-0">
                            <ScoreRing score={committee.score} size={80} />
                        </div>

                        {/* Main info */}
                        <div className="flex-1 min-w-0">
                            <div className="flex items-center gap-3 mb-2 flex-wrap">
                                <ShieldCheck size={16} className="text-[#d4af37]" />
                                <h2 className="text-xs font-black uppercase tracking-[0.2em] text-gray-400">
                                    Investment Committee Verdict
                                </h2>
                                <span
                                    className={`text-xs font-black px-2.5 py-1 rounded-lg border uppercase ${signalBg(committee.signal)} ${signalColor(committee.signal)}`}
                                    style={{ animation: "badgePop 0.5s cubic-bezier(0.34, 1.56, 0.64, 1) both" }}
                                >
