"use client";

import { useState, useEffect, useCallback } from "react";

// ─── Types ───────────────────────────────────────────────────────────────────

export interface HistoryAgentSummary {
    name: string;
    signal: string;
    confidence: number;
}

export interface HistoryEntry {
    id: string;          // "<TICKER>-<timestamp>"
    ticker: string;
    name: string;
    analyzedAt: string;  // ISO-8601
    signal: string;      // BUY | SELL | HOLD
    agentSummary: HistoryAgentSummary[];
    dalioVerdict: string;
    fromCache: boolean;
    // New fields for Portfolio Builder
    fundamental_score?: number;
    opportunity_score?: number;
    position_sizing?: any;
    sector?: string;
    dimensions?: any;
    timestamp?: string;
}

// ─── Constants ───────────────────────────────────────────────────────────────

const STORAGE_KEY = "365_history";
const MAX_ENTRIES = 50;

function loadFromStorage(): HistoryEntry[] {
    if (typeof window === "undefined") return [];
    try {
        const raw = localStorage.getItem(STORAGE_KEY);
        return raw ? (JSON.parse(raw) as HistoryEntry[]) : [];
    } catch {
        return [];
    }
}

function saveToStorage(entries: HistoryEntry[]) {
    try {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(entries));
    } catch {
        // quota exceeded — silently ignore
    }
}

// ─── Hook ────────────────────────────────────────────────────────────────────

export function useAnalysisHistory() {
    const [entries, setEntries] = useState<HistoryEntry[]>([]);
    const [hydrated, setHydrated] = useState(false);

    // SSR-safe hydration
    useEffect(() => {
        setEntries(loadFromStorage());
        setHydrated(true);
    }, []);

    const add = useCallback((entry: Omit<HistoryEntry, "id" | "analyzedAt">) => {
        const now = Date.now();
        const newEntry: HistoryEntry = {
            ...entry,
            id: `${entry.ticker}-${now}`,
            analyzedAt: new Date(now).toISOString(),
            timestamp: new Date(now).toISOString(),
        };
        setEntries((prev) => {
            // Newest first, capped at MAX_ENTRIES
            const updated = [newEntry, ...prev].slice(0, MAX_ENTRIES);
            saveToStorage(updated);
            return updated;
        });
    }, []);

    const removeById = useCallback((id: string) => {
        setEntries((prev) => {
            const updated = prev.filter((e) => e.id !== id);
            saveToStorage(updated);
            return updated;
        });
    }, []);

    const clear = useCallback(() => {
        setEntries([]);
        saveToStorage([]);
    }, []);

    return { entries, add, removeById, clear, hydrated };
}

"use client";

import { useState, useCallback, useRef } from "react";

export interface AgentSignal {
    agent_name: string;
    signal: string;
    confidence: number;
    analysis: string;
    key_metrics?: Record<string, unknown>;
    selected_metrics?: string[];
    discarded_metrics?: string[];
}

export interface DalioVerdict {
    final_verdict: string;
    dalio_response: {
        verdict?: string;
        risk_score?: number;
        allocation_rec?: string;
        summary_table?: string;
    };
}

export interface DataReadyPayload {
    ticker: string;
    name: string;
    tech_indicators: Record<string, unknown>;
    tradingview: Record<string, unknown>;
    fundamental_metrics: Record<string, unknown>;
    from_cache: boolean;
    cached_at: string | null;
}


export type StreamStatus =
    | "idle"
    | "fetching_data"
    | "analyzing"
    | "complete"
    | "error";

export interface AnalysisStreamState {
    status: StreamStatus;
    ticker: string;
    dataReady: DataReadyPayload | null;
    agents: AgentSignal[];
    dalio: DalioVerdict | null;
    error: string | null;
    agentCount: number;
    fromCache: boolean;
    cachedAt: string | null;
}


const TOTAL_AGENTS = 8;
const BACKEND_URL = "http://localhost:8000";

export function useAnalysisStream() {
    const [state, setState] = useState<AnalysisStreamState>({
        status: "idle",
        ticker: "",
        dataReady: null,
        agents: [],
        dalio: null,
        error: null,
        agentCount: 0,
        fromCache: false,
        cachedAt: null,
    });

    const esRef = useRef<EventSource | null>(null);
    const BACKEND_URL_LOCAL = BACKEND_URL;

    const analyze = useCallback((ticker: string, force = false) => {
        if (esRef.current) {
            esRef.current.close();
            esRef.current = null;
        }

        const symbol = ticker.trim().toUpperCase();
        if (!symbol) return;

        setState({
            status: "fetching_data",
            ticker: symbol,
            dataReady: null,
            agents: [],
            dalio: null,
            error: null,
            agentCount: 0,
            fromCache: false,
            cachedAt: null,
        });

        const url = `${BACKEND_URL}/analyze/stream?ticker=${encodeURIComponent(symbol)}${force ? "&force=true" : ""}`;
        const es = new EventSource(url);
        esRef.current = es;

        es.addEventListener("data_ready", (e: MessageEvent) => {
            const payload: DataReadyPayload = JSON.parse(e.data);
            setState((prev) => ({
                ...prev,
                status: "analyzing",
                dataReady: payload,
                fromCache: payload.from_cache ?? false,
                cachedAt: payload.cached_at ?? null,
            }));
        });

        // --- agent_update: one of the 8 agents finished ---
        es.addEventListener("agent_update", (e: MessageEvent) => {
            const agent: AgentSignal = JSON.parse(e.data);
            setState((prev) => ({
                ...prev,
                agents: [...prev.agents, agent],
                agentCount: prev.agentCount + 1,
            }));
        });

        // --- dalio_verdict: Dalio finished → stream is complete ---
        es.addEventListener("dalio_verdict", (e: MessageEvent) => {
            const verdict: DalioVerdict = JSON.parse(e.data);
            setState((prev) => ({
                ...prev,
                status: "complete",
                dalio: verdict,
            }));
            es.close();
            esRef.current = null;
        });

        // --- done: clean close without verdict (edge case) ---
        es.addEventListener("done", () => {
            setState((prev) => ({ ...prev, status: "complete" }));
            es.close();
            esRef.current = null;
        });

        // --- error event from server ---
        es.addEventListener("error", (e: MessageEvent) => {
            let message = "Unknown error from server";
            try {
                message = JSON.parse(e.data)?.message ?? message;
            } catch { }
            setState((prev) => ({ ...prev, status: "error", error: message }));
            es.close();
            esRef.current = null;
        });

        // --- onerror: network / connection problems ---
        es.onerror = () => {
            setState((prev) => {
                if (prev.status !== "complete") {
                    return {
                        ...prev,
                        status: "error",
                        error: "Connection to backend lost. Make sure the server is running.",
                    };
                }
                return prev;
            });
            es.close();
            esRef.current = null;
        };
    }, []);

    const reset = useCallback(() => {
        if (esRef.current) {
            esRef.current.close();
            esRef.current = null;
        }
        setState({
            status: "idle",
            ticker: "",
            dataReady: null,
            agents: [],
            dalio: null,
            error: null,
            agentCount: 0,
            fromCache: false,
            cachedAt: null,
        });
    }, []);

    /** Force-bypass the cache: invalidate on server then re-run. */
    const forceRefresh = useCallback(async (ticker: string) => {
        if (!ticker) return;
        const symbol = ticker.trim().toUpperCase();
        try {
            await fetch(`${BACKEND_URL}/cache/${encodeURIComponent(symbol)}`, { method: "DELETE" });
        } catch { /* ignore — still try to re-analyze */ }
        analyze(symbol, true);
    }, [analyze]);

    return { state, analyze, forceRefresh, reset, TOTAL_AGENTS };
}

export function useCSVExport() {
    const downloadCSV = (dataReady: any, techSummary: any, ticker: string) => {
        if (!dataReady) return;

        try {
            const rows: string[][] = [];
            const timestamp = new Date().toISOString();

            // HEADER
            rows.push(["TICKER", "NAME", "TIMESTAMP"]);
            rows.push([ticker, dataReady.name || ticker, timestamp]);
            rows.push([]);

            // FUNDAMENTAL RATIOS
            rows.push(["FUNDAMENTAL METRICS"]);
            if (dataReady.fundamental_metrics) {
                Object.entries(dataReady.fundamental_metrics).forEach(([category, metrics]: [string, any]) => {
                    rows.push([`-- ${category.toUpperCase()} --`]);
                    Object.entries(metrics).forEach(([key, val]: [string, any]) => {
                        rows.push([key, String(val)]);
                    });
                    rows.push([]);
                });
            }

            // TECHNICAL INDICATORS
            rows.push(["TECHNICAL INDICATORS"]);
            if (techSummary && techSummary.indicators) {
                Object.entries(techSummary.indicators).forEach(([category, data]: [string, any]) => {
                    rows.push([`-- ${category.toUpperCase()} --`]);
                    if (data.values) {
                        Object.entries(data.values).forEach(([key, val]: [string, any]) => {
                            let formattedVal = val;
                            if (typeof val === 'number') {
                                formattedVal = val.toFixed(2);
                            }
                            rows.push([key, String(formattedVal)]);
                        });
                    }
                    if (data.signals) {
                        Object.entries(data.signals).forEach(([key, val]: [string, any]) => {
                            rows.push([`${key} Signal`, String(val)]);
                        });
                    }
                    rows.push([]);
                });
            }

            const csvContent = rows.map((e) => e.join(",")).join("\n");
            const blob = new Blob([csvContent], { type: "text/csv;charset=utf-8;" });
            const url = URL.createObjectURL(blob);
            const link = document.createElement("a");

            link.setAttribute("href", url);
            link.setAttribute("download", `${ticker}_analysis_${new Date().getTime()}.csv`);
            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);

        } catch (e) {
            console.error("Failed to generate CSV", e);
        }
    };

    return { downloadCSV };
}

"use client";

import { useState, useCallback } from "react";
import type { OpportunityScore, PositionSizing } from "./useCombinedStream";

export interface PortfolioPositionInput {
    ticker: string;
    sector: string;
    opportunity_score: number;
    dimensions: Record<string, number>;
    position_sizing: PositionSizing;
}

export interface PortfolioPositionOutput {
    ticker: string;
    role: "CORE" | "SATELLITE";
    sector: string;
    target_weight: number;
}

export interface PortfolioRecommendationResult {
    total_allocation: number;
    core_allocation_total: number;
    satellite_allocation_total: number;
    risk_level: string;
    sector_exposures: Record<string, number>;
    core_positions: PortfolioPositionOutput[];
    satellite_positions: PortfolioPositionOutput[];
    violations_detected: string[];
}

const BACKEND_URL = process.env.NEXT_PUBLIC_API_URL ?? "http://localhost:8000";

export function usePortfolioBuilder() {
    const [isLoading, setIsLoading] = useState(false);
    const [result, setResult] = useState<PortfolioRecommendationResult | null>(null);
    const [error, setError] = useState<string | null>(null);

    const buildPortfolio = useCallback(async (positions: PortfolioPositionInput[]) => {
        setIsLoading(true);
        setError(null);
        try {
            const response = await fetch(`${BACKEND_URL}/portfolio/build`, {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                },
                body: JSON.stringify({ positions }),
            });

            if (!response.ok) {
                const txt = await response.text();
                throw new Error(txt || `Server error: ${response.status}`);
            }

            const data: PortfolioRecommendationResult = await response.json();
            setResult(data);
        } catch (err: any) {
            setError(err.message || "Failed to build portfolio");
        } finally {
            setIsLoading(false);
        }
    }, []);

    const reset = () => {
        setResult(null);
        setError(null);
    };

    return { buildPortfolio, result, isLoading, error, reset };
}

